"use client";

import { useState, useEffect } from "react";
import "@/styles/cyber-navabar.css";

const NAV_LINKS = [
  { label: "Lectures", href: "#" },
  { label: "CTF Arena", href: "#" },
  { label: "Codex", href: "#" },
  { label: "Labs", href: "#" },
  { label: "Leaderboard", href: "#" },
];

export default function CyberNavbar() {
  const [menuOpen, setMenuOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const [active, setActive] = useState(null);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 10);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  useEffect(() => {
    const onResize = () => {
      if (window.innerWidth >= 768) setMenuOpen(false);
    };
    window.addEventListener("resize", onResize);
    return () => window.removeEventListener("resize", onResize);
  }, []);

  return (
    <nav className={`cn-root${scrolled ? " scrolled" : ""}`}>
      <div className="cn-inner">

        <a className="cn-logo" href="/">
          <span className="cn-logo-prompt">~$</span>
          <span className="cn-logo-name">CyberNexus</span>
        </a>

        <ul className="cn-links">
          {NAV_LINKS.map(({ label, href }) => (
            <li key={label}>
              <a
                href={href}
                className={active === label ? "active" : ""}
                onClick={() => setActive(label)}
              >
                <span className="prefix">./</span>
                {label}
              </a>
            </li>
          ))}
        </ul>

        <div className="cn-right">
          <span className="cn-live">
            <span className="cn-live-dot" />
            LIVE
          </span>

          <div className="cn-divider" />

          <button className="cn-btn-ghost">Enroll</button>
          <button className="cn-btn-primary">Sign In</button>

          <button
            className={`cn-hamburger${menuOpen ? " open" : ""}`}
            onClick={() => setMenuOpen(!menuOpen)}
          >
            <span /><span /><span />
          </button>
        </div>
      </div>

      <div className={`cn-mobile${menuOpen ? " open" : ""}`}>
        {NAV_LINKS.map(({ label, href }) => (
          <a
            key={label}
            href={href}
            className={`cn-mobile-link${active === label ? " active" : ""}`}
            onClick={() => {
              setActive(label);
              setMenuOpen(false);
            }}
          >
            <span className="prefix">$</span>
            {label}
          </a>
        ))}

        <div className="cn-mobile-actions">
          <button className="cn-btn-ghost">Enroll</button>
          <button className="cn-btn-primary">Sign In</button>
        </div>
      </div>
    </nav>
  );
}
